  const [isMultiMode, setIsMultiMode] = useState(false);
  const [activeFoundationCategory, setActiveFoundationCategory] = useState<string>('asian');
  const [isCustomFoundation, setIsCustomFoundation] = useState(false);

  const filteredShades = useMemo(() => {
    return FOUNDATION_SHADES.filter(s => s.category === activeFoundationCategory);
  }, [activeFoundationCategory]);

  const handlePresetChange = (presetId: string) => {
    const defaults = PRESET_DEFAULTS[presetId];
    updateState({ makeup: { ...state.makeup, makeupStyle: presetId, ...(defaults || {}) } });
  };

  const handleFeatureChange = useCallback((key: string, value: any) => { updateState({ features: { ...state.features, [key]: value } }); }, [state.features, updateState]);
  const handleMakeupChange = useCallback((id: string, value: any) => { 
    if (id === 'foundationTone' && !isCustomFoundation && value.startsWith('#')) {
      // If we are setting a hex but not in custom mode, we might want to stay in custom mode
    }
    updateState({ makeup: { ...state.makeup, [id]: value } }); 
  }, [state.makeup, updateState, isCustomFoundation]);

  const handleHairChange = useCallback((id: string, value: any) => { updateState({ hair: { ...state.hair, [id]: value } }); }, [state.hair, updateState]);
  const handleSkinChange = useCallback((id: string, value: any) => { updateState({ skin: { ...state.skin, [id]: value } }); }, [state.skin, updateState]);
  const handleCustomPromptChange = useCallback((category: keyof BeautyState['customPrompts'], value: string) => { updateState({ customPrompts: { ...state.customPrompts, [category]: value } }); }, [state.customPrompts, updateState]);
