                    <SubSection title="Quality & Volume" defaultOpen={false}>
                      <div className="space-y-4"><div className="space-y-2"><div className="flex justify-between text-[10px] font-bold"><span className="text-zinc-500">Volume</span><span className="text-rose-400">{state.hair.hairVolume}</span></div><input type="range" min="0" max="100" value={state.hair.hairVolume} onChange={(e) => handleHairChange('hairVolume', parseInt(e.target.value))} className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" /></div><div className="space-y-2"><div className="flex justify-between text-[10px] font-bold items-center"><div className="flex items-center gap-1"><Sparkles className="w-3 h-3 text-rose-400" /><span className="text-zinc-500">Hair Shine</span></div><span className="text-rose-400">{state.hair.hairShine}%</span></div><input type="range" min="0" max="100" value={state.hair.hairShine} onChange={(e) => handleHairChange('hairShine', parseInt(e.target.value))} className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" /></div></div>
                    </SubSection>
                    <SubSection title="Color Studio" defaultOpen={false}>
                      <div className="space-y-4"><ColorSection label="Root Color" id="hairColorTop" presets={HAIR_COLOR_PRESETS} colorValue={state.hair.hairColorTop} disabled={false} onColorChange={handleHairChange} /><div className="space-y-2"><div className="flex justify-between text-[10px] font-bold items-center"><div className="flex items-center gap-1"><Split className="w-3 h-3 text-rose-400" /><span className="text-zinc-500">Gradient Transition</span></div><span className="text-rose-400">{state.hair.hairColorBoundary}%</span></div><input type="range" min="0" max="100" value={state.hair.hairColorBoundary} onChange={(e) => handleHairChange('hairColorBoundary', parseInt(e.target.value))} className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" /></div><ColorSection label="Ends Color" id="hairColorBottom" presets={HAIR_COLOR_PRESETS} colorValue={state.hair.hairColorBottom} disabled={false} onColorChange={handleHairChange} /></div>
                    </SubSection>
                  </div>
                </div>
                {renderRefUploader('hair', 'Hair')}
              </CategoryAccordion>
            )}

            {state.editModes.makeup && (
              <CategoryAccordion title="Makeup Artist" icon={Brush} onOpenHelp={() => setActiveHelpId('makeup')} onReset={() => onResetCategory('makeup')}>
                <div className="relative">
                  {state.referenceImages.makeup && <LockOverlay category="Makeup" />}
                  <div className={state.referenceImages.makeup ? 'opacity-20 pointer-events-none filter blur-[1px]' : ''}>

                    {/* ENHANCED Foundation Guide Section */}
                    <SubSection title="Base Guide" defaultOpen={true}>
                      <div className="space-y-5">
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-2 text-rose-400"><Pipette className="w-3.5 h-3.5" /><span className="text-[10px] font-black uppercase tracking-[0.15em]">Base Tone</span></div>
                          <button 
                            onClick={() => {
                              setIsCustomFoundation(false);
                              handleMakeupChange('foundationTone', 'none');
                            }}
                            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[9px] font-bold border transition-all ${state.makeup.foundationTone === 'none' && !isCustomFoundation ? 'bg-rose-500/10 border-rose-500/30 text-rose-400' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-zinc-300'}`}
                          >
                            <Undo2 className="w-3 h-3" /> Original
                          </button>
                        </div>

                        {/* Text-based Category Selector */}
                        <div className="grid grid-cols-2 gap-1.5">
                          {FOUNDATION_CATEGORIES.filter(c => c.id !== 'none').map(cat => (
                            <button
                              key={cat.id}
                              onClick={() => {
                                setIsCustomFoundation(false);
                                setActiveFoundationCategory(cat.id);
                              }}
                              className={`py-2 px-3 rounded-xl text-[10px] font-bold uppercase transition-all border text-center ${!isCustomFoundation && activeFoundationCategory === cat.id ? 'bg-zinc-800 border-indigo-500 text-indigo-400' : 'bg-zinc-900/40 border-zinc-800/50 text-zinc-600 hover:text-zinc-400'}`}
                            >
                              {cat.label.split('/')[0]}
                            </button>
                          ))}
                          {/* Custom Category Button */}
                          <button
                             onClick={() => setIsCustomFoundation(true)}
                             className={`py-2 px-3 rounded-xl text-[10px] font-bold uppercase transition-all border text-center ${isCustomFoundation ? 'bg-zinc-800 border-rose-500 text-rose-400' : 'bg-zinc-900/40 border-zinc-800/50 text-zinc-600 hover:text-zinc-400'}`}
