                        {/* Shade Display */}
                        {isCustomFoundation ? (
                          <div className="p-4 bg-zinc-900/40 rounded-2xl border border-zinc-800 animate-in fade-in zoom-in-95 duration-200">
                             <ColorSection 
                                label="Bespoke Base Shade" 
                                id="foundationTone" 
                                presets={[]} 
                                colorValue={state.makeup.foundationTone.startsWith('#') ? state.makeup.foundationTone : '#f4d5bc'} 
