                                onColorChange={handleMakeupChange} 
                             />
                             <p className="mt-3 text-[9px] text-zinc-600 font-medium">Fine-tune the perfect foundation shade manually.</p>
                          </div>
                        ) : (
                          <div className="space-y-3 animate-in fade-in slide-in-from-top-1 duration-200">
                             <div className="flex flex-wrap gap-2 p-3 bg-black/30 rounded-2xl border border-zinc-800/50">
                                {filteredShades.map(shade => (
                                  <button
                                    key={shade.id}
                                    onClick={() => handleMakeupChange('foundationTone', shade.id)}
                                    className={`relative w-8 h-8 rounded-full border-2 transition-all ${state.makeup.foundationTone === shade.id ? 'border-rose-400 scale-110 shadow-lg shadow-rose-400/20' : 'border-zinc-800 hover:border-zinc-600'}`}
                                    style={{ backgroundColor: shade.color }}
                                    title={shade.label}
                                  >
                                    {state.makeup.foundationTone === shade.id && (
                                      <div className="absolute inset-0 flex items-center justify-center">
                                         <Check className="w-3 h-3 text-white drop-shadow-md" strokeWidth={4} />
                                      </div>
                                    )}
                                  </button>
                                ))}
                             </div>
                             <div className="px-1 flex justify-between items-center">
                                <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">
                                   {FOUNDATION_SHADES.find(s => s.id === state.makeup.foundationTone)?.label || 'Select a shade'}
                                </span>
                             </div>
                          </div>
                        )}
                      </div>
                    </SubSection>

                    <SubSection title="Concept & Finish" defaultOpen={false}>
                      <div className="space-y-4">
                        <div className="flex items-center gap-2">
                          {state.makeup.makeupStyle === 'Custom Look' ? <MousePointer2 className="w-3.5 h-3.5 text-rose-400" /> : <Palette className="w-3.5 h-3.5 text-rose-400" />}
                          <span className="text-[10px] font-black uppercase tracking-widest text-zinc-300">Style Preset</span>
                        </div>
                        <select 
                          value={state.makeup.makeupStyle} 
                          onChange={(e) => handlePresetChange(e.target.value)} 
                          className={`w-full bg-zinc-900 border rounded-xl px-4 py-3 text-[11px] font-bold outline-none transition-all ${state.makeup.makeupStyle === 'Custom Look' ? 'border-rose-500/50 text-rose-300' : 'border-zinc-800 text-zinc-300 focus:border-rose-400'}`}
                        >
                          {MAKEUP_STYLES.map(style => (<option key={style.id} value={style.id}>{style.label}</option>))}
                        </select>
                      </div>
                    </SubSection>
                    <SubSection title="Eye Makeup" defaultOpen={true}>
                      <div className="space-y-4"><ColorSection label="Eyebrow Color" id="eyebrowColor" presets={MAKEUP_PRESETS.eyebrow} colorValue={state.makeup.eyebrowColor} disabled={false} onColorChange={handleMakeupChange} /><div className="space-y-2"><span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Eyeliner</span><StyleSelector options={EYELINER_STYLES} selectedId={state.makeup.eyelinerStyle} onSelect={(id) => handleMakeupChange('eyelinerStyle', id)} /></div><div className="space-y-2"><span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Lashes</span><StyleSelector options={EYELASH_STYLES} selectedId={state.makeup.eyelashStyle} onSelect={(id) => handleMakeupChange('eyelashStyle', id)} /></div><ColorSection label="Eyeshadow" id="eyeshadowColor" presets={MAKEUP_PRESETS.eyeshadow} colorValue={state.makeup.eyeshadowColor} disabled={false} onColorChange={handleMakeupChange} /></div>
                    </SubSection>
                    <SubSection title="Cheek & Shading" defaultOpen={false}>
                      <div className="space-y-4"><div className="space-y-2"><span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Blush Style</span><StyleSelector options={BLUSH_STYLES} selectedId={state.makeup.blushStyle} onSelect={(id) => handleMakeupChange('blushStyle', id)} /></div><ColorSection label="Blush Color" id="blushColor" presets={MAKEUP_PRESETS.blush} colorValue={state.makeup.blushColor} disabled={false} onColorChange={handleMakeupChange} /><div className="space-y-2"><div className="flex justify-between text-[10px] font-bold"><span className="text-zinc-500">Blush Intensity</span><span className="text-rose-400">{state.makeup.blushIntensity}</span></div><input type="range" min="0" max="100" value={state.makeup.blushIntensity} onChange={(e) => handleMakeupChange('blushIntensity', parseInt(e.target.value))} className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" /></div><div className="space-y-2"><div className="flex justify-between text-[10px] font-bold"><span className="text-zinc-500">Contour Shading</span><span className="text-indigo-400">{state.makeup.contourIntensity}</span></div><input type="range" min="0" max="100" value={state.makeup.contourIntensity} onChange={(e) => handleMakeupChange('contourIntensity', parseInt(e.target.value))} className="w-full accent-indigo-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" /></div></div>
                    </SubSection>
                    <SubSection title="Lip & Finish" defaultOpen={false}>
                      <div className="space-y-4"><div className="space-y-2"><span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Lip Finish</span><StyleSelector options={LIP_STYLES} selectedId={state.makeup.lipStyle} onSelect={(id) => handleMakeupChange('lipStyle', id)} /></div><ColorSection label="Lip Color" id="lipColor" presets={MAKEUP_PRESETS.lipstick} colorValue={state.makeup.lipColor} disabled={false} onColorChange={handleMakeupChange} /></div>
                    </SubSection>
                  </div>
                </div>
                <div className="space-y-3 pt-5 border-t border-zinc-900">
                  <div className="flex items-center gap-2 text-zinc-500"><MessageSquareText className="w-3 h-3" /><span className="text-[9px] font-bold uppercase tracking-widest">Artist Notes</span></div>
                  <textarea value={state.customPrompts.makeup} onChange={(e) => handleCustomPromptChange('makeup', e.target.value)} placeholder="Glitter, matte finish, or specific reference..." className="w-full h-20 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-[10px] text-zinc-300 outline-none focus:border-rose-400 transition-all resize-none" />
                </div>
                {renderRefUploader('makeup', 'Makeup')}
              </CategoryAccordion>
            )}
          </div>
        )}
      </div>
      <div className="p-4 bg-zinc-950 border-t border-zinc-900"><div className="flex items-center gap-2 text-rose-400 mb-1"><Zap className="w-3 h-3 fill-current" /><span className="text-[9px] font-bold uppercase tracking-widest">Context Engine v7.5</span></div><p className="text-[10px] text-zinc-600 leading-tight">Smart Reference & Preset Logic Enabled.</p></div>
    </aside>
  );
};

export interface FacialFeatures {
  eyeSize: number;
  lipThickness: number;
  noseWidth: number;
  eyelidType: 'Monolid' | 'Double' | 'Hooded';
  jawlineSharpness: number;
  canthalTilt: number; // eyeTilt
  jawShape: number;
  cheekboneHeight: number;
  faceWidth: number;
  eyeDistance: number;
  noseBridge: number;
  mouthCorners: number;
  lipCupidBow: number;
}

export interface SkinFeatures {
  tone: string;
  texture: string[];
  skinAge: number;
  glowIntensity: number;
  blemishIntensity: number;
}

export interface HairFeatures {
  hairStyle: string;
  hairLength: 'pixie' | 'leaf' | 'bob' | 'medium' | 'long' | 'extra_long';
  hairTexture: 'straight' | 'c_curl' | 's_curl' | 'jelly' | 'hippie' | 'hershey' | 'hime';
  bangStyle: 'none' | 'see_through' | 'full_blunt' | 'side' | 'choppy' | 'onion';
  hairVolume: number;
  hairShine: number;
  hairColorTop: string;
  hairColorBottom: string;
  hairColorBoundary: number;
}

export interface MakeupFeatures {
  makeupStyle: string;
  foundationTone: string;
  eyebrowStyle: 'standard' | 'high_arch' | 'straight' | 'curved' | 'thin' | 'soft_arch';
  eyebrowColor: string;
  eyelinerStyle: 'none' | 'tightline' | 'classic' | 'puppy' | 'cat' | 'siren' | 'bold' | 'smoky';
  eyelashStyle: 'natural' | 'mascara' | 'idol' | 'volume' | 'under';
  eyeshadowColor: string;
  eyelinerIntensity: number;
  blushStyle: 'none' | 'apples' | 'side' | 'drunken' | 'sunburn';
  blushColor: string;
  blushIntensity: number;
  contourIntensity: number;
  lipStyle: 'matte_blur' | 'glossy_tanghulu' | 'gradient' | 'overlip' | 'mlbb';
  lipColor: string;
  lipstickGloss: number;
}

export interface CustomPreset {
  id: string;
  name: string;
  config: Partial<MakeupFeatures>;
}

export interface BeautyState {
  baseImage: string | null;
  referenceImages: {
    face: string | null;
    skin: string | null;
    hair: string | null;
    makeup: string | null;
  };
  features: FacialFeatures;
  skin: SkinFeatures;
  hair: HairFeatures;
  makeup: MakeupFeatures;
  customMakeupPresets: CustomPreset[];
  customPrompts: {
    face: string;
    skin: string;
    hair: string;
    makeup: string;
  };
  editModes: {
    face: boolean;
    skin: boolean;
    hair: boolean;
    makeup: boolean;
  };
  aspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
  baseline?: {
    features: Partial<FacialFeatures>;
    skin: Partial<SkinFeatures>;
    hair?: {
      hairLength: HairFeatures['hairLength'];
      hairTexture: HairFeatures['hairTexture'];
    };
  };
}

export enum TabType {
  FEATURES = 'FEATURES',
  SKIN = 'SKIN',
  HAIR = 'HAIR',
  MAKEUP = 'MAKEUP'
}

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes, analyzeResultingAesthetics } from './services/geminiService';
import { BeautyState, CustomPreset } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Activity, Copy, Check, Loader2 } from 'lucide-react';

const PRESETS_STORAGE_KEY = 'beautysynth_custom_presets';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customMakeupPresets: [],
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [resultAnalysis, setResultAnalysis] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  // Load custom presets from localStorage on init
  useEffect(() => {
    const saved = localStorage.getItem(PRESETS_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, customMakeupPresets: parsed }));
      } catch (e) {
        console.error("Failed to parse saved presets", e);
      }
    }

    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  // Save custom presets to localStorage when they change
  useEffect(() => {
    localStorage.setItem(PRESETS_STORAGE_KEY, JSON.stringify(state.customMakeupPresets));
  }, [state.customMakeupPresets]);

  const calculateAspectRatio = (img: HTMLImageElement): any => {
    const ratio = img.width / img.height;
    const options: { label: string, value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const applyAnalysis = async (data: any, originalImage: string, detectedRatio: any) => {
    const scale = (val: any) => {
      if (typeof val !== 'number') return 50;
      return val <= 1 ? Math.round(val * 100) : Math.round(val);
    };

    const skinToneVal = scale(data.skinTone);
    const skinToneId = skinToneVal < 20 ? 'porcelain' 
                     : skinToneVal < 40 ? 'fair' 
                     : skinToneVal < 60 ? 'natural' 
                     : skinToneVal < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;

    const analyzedFeatures = {
      ...INITIAL_FEATURES,
      eyeSize: scale(data.eyeSize ?? 50),
      canthalTilt: scale(data.eyeTilt ?? 50),
      noseBridge: scale(data.noseBridge ?? 50),
      noseWidth: scale(data.noseWidth ?? 50),
      faceWidth: scale(data.faceWidth ?? 50),
      cheekboneHeight: scale(data.cheekboneHeight ?? 50),
      jawShape: scale(data.jawShape ?? 50),
      lipThickness: scale(data.lipFullness ?? 50),
    };

    const analyzedSkin = {
      ...state.skin,
      tone: skinToneId,
      skinAge: scale(data.skinAge ?? 20),
    };

    const analyzedHair = {
      ...state.hair,
      hairLength: hairLen,
      hairTexture: hairTex,
    };

    setState(prev => ({
      ...prev,
      baseImage: originalImage,
      aspectRatio: detectedRatio,
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: {
        features: analyzedFeatures,
        skin: analyzedSkin,
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      setResultAnalysis(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
        const analysis = await analyzeResultingAesthetics(result);
        setResultAnalysis(analysis);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    const currentAsBaseline = {
      features: { ...state.features },
      skin: { ...state.skin },
      hair: { hairLength: state.hair.hairLength, hairTexture: state.hair.hairTexture }
    };
    updateState({ baseImage: generatedImage, baseline: currentAsBaseline });
    setGeneratedImage(null);
    setResultAnalysis(null);
    setIsComparing(false);
  };

  const handleCopyAnalysis = () => {
    if (resultAnalysis) {
      navigator.clipboard.writeText(resultAnalysis);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }
  };

  const handleDeleteBaseImage = () => {
    updateState({ baseImage: null, baseline: undefined });
    setGeneratedImage(null);
    setResultAnalysis(null);
  };

  const handleResetCategory = (category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const updates: any = {};
      if (category === 'face') {
        updates.features = prev.baseline ? { ...INITIAL_FEATURES, ...prev.baseline.features } : INITIAL_FEATURES;
      } else if (category === 'skin') {
        updates.skin = prev.baseline ? { ...prev.skin, ...prev.baseline.skin } : { ...prev.skin, tone: 'natural', skinAge: 20 };
      } else if (category === 'hair') {
        updates.hair = prev.baseline && prev.baseline.hair ? { ...prev.hair, ...prev.baseline.hair } : INITIAL_HAIR;
      } else if (category === 'makeup') {
        updates.makeup = INITIAL_MAKEUP;
      }
      return { ...prev, ...updates };
    });
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const detectedRatio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: detectedRatio, baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String, detectedRatio);
            } catch (err) {
              setError("AI analysis failed.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-[#050505] overflow-hidden text-zinc-100 selection:bg-indigo-500/30">
