const getSliderAdjective = (value: number, type: string): string => {
  const isExtremeHigh = value >= 85;
  const isHigh = value >= 65 && value < 85;
  const isLow = value <= 35 && value > 15;
  const isExtremeLow = value <= 15;

  if (isExtremeHigh) {
    switch (type) {
      case 'faceWidth': return "EXTREMELY BROAD; expansive and powerful facial architecture";
      case 'jawlineSharpness': return "HYPER-DEFINED; razor-sharp, bone-deep jaw definition";
      case 'jawShape': return "STRONG SQUARE JAW; sharp L-line masculine/aristocratic bone structure";
      case 'eyeSize': return "EXTREME ENLARGEMENT; massive doll-like eyes, wide-open aperture";
      case 'lipThickness': return "MAXIMUM PLUMP; significant volume, extremely full and thick lips";
      case 'noseWidth': return "PRONOUNCED WIDE; strong, broad nasal base";
      case 'canthalTilt': return "MAXIMUM UPWARD LIFT; aggressive feline/siren eye tilt, outer corner significantly higher than inner";
      case 'cheekboneHeight': return "EXTREME HIGH-PROJECTION; dramatic skeletal couture-model cheekbones";
      case 'eyeDistance': return "ULTRA WIDE-SET; expansive distance between eyes";
      case 'noseBridge': return "TALL PROMINENT BRIDGE; very high Grecian profile";
      case 'mouthCorners': return "EXTREME UPTURN; dramatic permanent smile expression. Morph only the corner contours, keep lip color intact.";
      case 'lipCupidBow': return "EXTREME M-SHAPE; sharp, pointed, deep cupid's bow peaks";
      case 'skinAge': return "VERY MATURE; deep realistic wrinkles and textured skin";
    }
  }

  if (isHigh) {
    switch (type) {
      case 'faceWidth': return "noticeably broad and wider facial frame";
      case 'jawlineSharpness': return "sharply defined and clear jawline shadow";
      case 'jawShape': return "clearly defined angular jaw structure";
      case 'eyeSize': return "larger, more expressive eyes";
      case 'lipThickness': return "noticeably fuller and thicker lips";
      case 'noseWidth': return "broad and stronger nose shape";
      case 'canthalTilt': return "clearly upturned and lifted outer eye corners, sharp feline look";
      case 'cheekboneHeight': return "pronounced and high cheekbone definition";
      case 'eyeDistance': return "noticeably wide-set eye positioning";
      case 'noseBridge': return "strong and elevated nasal bridge";
      case 'mouthCorners': return "cheerfully upturned lip corners into a smile. Morph geometric lines only.";
      case 'lipCupidBow': return "well-defined and sharp cupid's bow";
      case 'skinAge': return "showing mature texture and light character lines";
    }
  }

  if (isExtremeLow) {
    switch (type) {
      case 'faceWidth': return "ULTRA-SLENDER; physically very narrow, fragile delicate skull";
      case 'jawlineSharpness': return "COMPLETE SOFT-FOCUS; no bone definition, rounded transition to neck";
      case 'jawShape': return "FULL ROUNDED LOWER FACE; complete absence of bone, chubby youthful curves, maximum facial fat";
      case 'eyeSize': return "MINIMALIST; very small, tight, or heavily hooded eyes";
      case 'lipThickness': return "ULTRA-THIN; nearly invisible vertical lip height, very narrow";
      case 'noseWidth': return "EXTREMELY PINCHED; needle-thin nasal base and nostrils";
      case 'canthalTilt': return "MAXIMUM DOWNWARD ROTATION; outer eye corner is lower than inner corner. Keep eyes alert.";
      case 'cheekboneHeight': return "TOTAL MIDFACE FULLNESS; flat bone structure, fully rounded fleshy cheeks with no skeletal protrusion";
      case 'eyeDistance': return "ULTRA CLOSE-SET; eyes positioned very close to the nose";
      case 'noseBridge': return "FLAT BUTTON NOSE; nearly absent nasal bridge profile";
      case 'skinAge': return "PORCELAIN SMOOTH; zero texture, fetal-level blur and softness";
    }
  }

  if (isLow) {
    switch (type) {
      case 'faceWidth': return "noticeably narrow and slim facial shape";
      case 'jawlineSharpness': return "soft and rounded jawline transition";
      case 'jawShape': return "youthful, round, and soft jaw profile with fuller cheeks";
      case 'eyeSize': return "smaller, subtle aesthetic eyes";
      case 'lipThickness': return "slim and thin lip appearance";
      case 'noseWidth': return "narrow and petite nose width";
      case 'canthalTilt': return "downward rotated eye axis; outer corner lower than inner corner.";
      case 'cheekboneHeight': return "smooth and soft midface with minimal bone projection and added facial volume";
      case 'eyeDistance': return "close-set eye positioning";
      case 'noseBridge': return "low and soft nasal bridge";
      case 'skinAge': return "very smooth and youthful skin appearance";
    }
  }

  return `neutral/standard ${type}`;
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: Strictly maintain current ${type}.`;
  const diff = current - baseline;
  const absDiff = Math.abs(diff);

  if (absDiff < 5) return `FIXED: Strictly keep the original ${type} unchanged.`;

  let intensityVerb = "slightly adjust";
  if (absDiff > 40) intensityVerb = "DRAMATICALLY OVERHAUL and EXAGGERATE";
  else if (absDiff > 20) intensityVerb = "SIGNIFICANTLY MORPH";
  else intensityVerb = "NOTICEABLY modify";

  let action = "";
  if (diff > 0) {
    action = (type === 'mouthCorners') ? "forcefully lift and curve upwards into a visible smile contour" : "increase/sharpen/widen";
  } else {
    action = (type === 'jawShape' || type === 'cheekboneHeight') ? "heavily add soft tissue/flesh and round out into a plump curve, removing skeletal definition" : "decrease/soften/shrink/round";
  }

  return `MORPH GEOMETRY: ${intensityVerb} the ${type} to be ${getSliderAdjective(current, type)}. IMPORTANT: Only change the structural shape, do not alter surface colors or makeup pigments in this area.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: { 
        parts: [
          { inlineData: { data, mimeType } }, 
          { text: "Detailed anatomical facial analysis. Determine facial and skin percentages as INTEGERS between 0 and 100 (e.g., 50, 85). Return ONLY JSON." }
        ] 
      },
      config: { 
        responseMimeType: "application/json", 
        responseSchema: { 
          type: Type.OBJECT, 
          properties: { 
            skinTone: { type: Type.NUMBER, description: "Skin tone percentage 0-100" }, 
            skinAge: { type: Type.NUMBER, description: "Skin age percentage 0-100" }, 
            eyeSize: { type: Type.NUMBER, description: "Eye size percentage 0-100" }, 
            eyeTilt: { type: Type.NUMBER, description: "Eye tilt percentage 0-100" }, 
            noseBridge: { type: Type.NUMBER, description: "Nose bridge height percentage 0-100" }, 
            noseWidth: { type: Type.NUMBER, description: "Nose width percentage 0-100" }, 
            faceWidth: { type: Type.NUMBER, description: "Face width percentage 0-100" }, 
            cheekboneHeight: { type: Type.NUMBER, description: "Cheekbone height percentage 0-100" }, 
            jawShape: { type: Type.NUMBER, description: "Jaw shape percentage 0-100" }, 
            lipFullness: { type: Type.NUMBER, description: "Lip fullness percentage 0-100" }, 
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] }, 
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] } 
          }, 
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"] 
        } 
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) { throw error; }
};

export const analyzeResultingAesthetics = async (base64Image: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze this beauty portrait and provide a high-quality, professional photography prompt that describes it. Focus on model characteristics, skin texture, lighting, camera settings (like lens), and overall mood. The output should be a single, detailed paragraph." }
        ]
      }
    });
    return response.text || "Analysis unavailable.";
  } catch (error) {
    return "Result Analysis failed.";
  }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages, customPrompts } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "STRICT LOCK: Keep original facial structure and bones perfectly identical. Do not change expression or facial shape.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Replicate exact bone structure and eye positioning from FACIAL REF onto the subject.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) mods.push(`EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}`);

    faceIns = `STRUCTURAL MODIFICATION: ${mods.join(" | ")}. ${customPrompts.face ? `CUSTOM FACE NOTE: ${customPrompts.face}` : ''}`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: Preserve all existing makeup colors and styles from the base image exactly.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    let foundationPrompt = "Foundation Base: Strictly preserve and anchor the original skin color and tone as seen in the base image.";
    if (makeup.foundationTone !== 'none') {
      const preset = FOUNDATION_SHADES.find(s => s.id === makeup.foundationTone);
      if (preset) {
        foundationPrompt = `Foundation Base: Apply a full-coverage layer of ${preset.prompt}. This new tone must completely override the old skin tone while keeping detail.`;
      } else if (makeup.foundationTone.startsWith('#')) {
        foundationPrompt = `Foundation Base: Apply a professional layer of custom foundation with hex color ${makeup.foundationTone}. Seal this color across all visible skin areas.`;
      }
    }

    const blushDesc = makeup.blushStyle !== 'none' 
      ? `Blush: Apply ${makeup.blushColor} in ${makeup.blushStyle} style with ${makeup.blushIntensity}% intensity.` 
      : "Blush: None.";
    const contourDesc = `Contour: Apply ${makeup.contourIntensity}% depth shading.`;

    makeIns = `ARTISTRY: ${makeup.makeupStyle}. ${foundationPrompt}. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}. Lips: ${makeup.lipColor} pigment in ${makeup.lipStyle} finish. ${blushDesc} ${contourDesc}. Ensure makeup colors are vibrant and clearly defined. ${customPrompts.makeup ? `ARTIST NOTE: ${customPrompts.makeup}` : ''}`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Maintain exact original skin tone and texture without any shifting.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and tone from SKIN REF.";
  } else {
    const skinStyle = SKIN_TEXTURES.find(t => t.id === skin.texture[0])?.prompt || "smooth skin";
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skinStyle}. Glow: ${skin.glowIntensity}%, Age: ${skin.skinAge}%, Blemish detail: ${skin.blemishIntensity}%. ${customPrompts.skin ? `SKIN NOTE: ${customPrompts.skin}` : ''}`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
    hairIns = `HAIR: ${hair.hairLength} length ${hair.hairTexture}. Bangs: ${selectedBang}. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%. ${customPrompts.hair ? `HAIR NOTE: ${customPrompts.hair}` : ''}`;
  }

  return `Task: High-End Editorial Retouching. 
    FACIAL STRUCTURE (MORPH ONLY WHERE SPECIFIED): ${faceIns} 
    SURFACE COLORS & MAKEUP: ${makeIns}
    SKIN QUALITY: ${skinIns} 
    HAIR: ${hairIns} 
    CRITICAL MANDATE: Separate Geometry from Color. Morphological changes (like mouth corners) must not shift or bleed into the makeup pigment colors or the general skin tone. If Foundation is 'none', you MUST use the exact RGB values from the source image for the skin. Output 2K Ultra HD realistic portrait. Preserve original background.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "SOURCE BASE IMAGE (USE AS ANCHOR FOR COLOR AND TONE)" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  const addRef = (category: keyof typeof state.referenceImages, label: string) => {
    if (state.editModes[category] && state.referenceImages[category]) {
      const [header, data] = state.referenceImages[category]!.split(';base64,');
      parts.push({ text: `${label} REF IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  };

  addRef('hair', 'HAIR');
  addRef('makeup', 'MAKEUP');
  addRef('skin', 'SKIN');
  addRef('face', 'FACIAL');

  try {
    const response = await ai.models.generateContent({ 
      model: 'gemini-3-pro-image-preview', 
      contents: { parts }, 
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } 
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { throw error; }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes, analyzeResultingAesthetics } from './services/geminiService';
import { BeautyState, CustomPreset } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Activity, Copy, Check, Loader2 } from 'lucide-react';

const PRESETS_STORAGE_KEY = 'beautysynth_custom_presets';

const App: React.FC = () => {
  // Use lazy initialization for state to ensure localStorage is read BEFORE first render
  const [state, setState] = useState<BeautyState>(() => {
    let savedPresets: CustomPreset[] = [];
    try {
      const saved = localStorage.getItem(PRESETS_STORAGE_KEY);
      if (saved) {
        savedPresets = JSON.parse(saved);
      }
    } catch (e) {
      console.error("Failed to load presets from storage", e);
    }

    return {
      baseImage: null,
      referenceImages: {
        face: null,
        skin: null,
        hair: null,
        makeup: null
      },
      features: INITIAL_FEATURES,
      skin: { 
        tone: 'natural', 
        texture: ['Smooth'],
        skinAge: 20,
        glowIntensity: 50,
        blemishIntensity: 10
      },
      hair: INITIAL_HAIR,
      makeup: INITIAL_MAKEUP,
      customMakeupPresets: savedPresets, // Initialized from storage
      customPrompts: {
        face: '',
        skin: '',
        hair: '',
        makeup: ''
      },
      editModes: {
        face: false,
        skin: false,
        hair: false,
        makeup: false
      },
      aspectRatio: '1:1',
      baseline: undefined
    };
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [resultAnalysis, setResultAnalysis] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  // Sync custom presets to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(PRESETS_STORAGE_KEY, JSON.stringify(state.customMakeupPresets));
  }, [state.customMakeupPresets]);

  const calculateAspectRatio = (img: HTMLImageElement): any => {
    const ratio = img.width / img.height;
    const options: { label: string, value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const applyAnalysis = async (data: any, originalImage: string, detectedRatio: any) => {
    const scale = (val: any) => {
      if (typeof val !== 'number') return 50;
      return val <= 1 ? Math.round(val * 100) : Math.round(val);
    };

    const skinToneVal = scale(data.skinTone);
    const skinToneId = skinToneVal < 20 ? 'porcelain' 
                     : skinToneVal < 40 ? 'fair' 
                     : skinToneVal < 60 ? 'natural' 
                     : skinToneVal < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;

    const analyzedFeatures = {
      ...INITIAL_FEATURES,
      eyeSize: scale(data.eyeSize ?? 50),
      canthalTilt: scale(data.eyeTilt ?? 50),
      noseBridge: scale(data.noseBridge ?? 50),
      noseWidth: scale(data.noseWidth ?? 50),
      faceWidth: scale(data.faceWidth ?? 50),
      cheekboneHeight: scale(data.cheekboneHeight ?? 50),
      jawShape: scale(data.jawShape ?? 50),
      lipThickness: scale(data.lipFullness ?? 50),
    };

    const analyzedSkin = {
      ...state.skin,
      tone: skinToneId,
      skinAge: scale(data.skinAge ?? 20),
    };

    const analyzedHair = {
      ...state.hair,
      hairLength: hairLen,
      hairTexture: hairTex,
    };

    setState(prev => ({
      ...prev,
      baseImage: originalImage,
      aspectRatio: detectedRatio,
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: {
        features: analyzedFeatures,
        skin: analyzedSkin,
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      setResultAnalysis(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
        const analysis = await analyzeResultingAesthetics(result);
        setResultAnalysis(analysis);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    const currentAsBaseline = {
      features: { ...state.features },
      skin: { ...state.skin },
      hair: { hairLength: state.hair.hairLength, hairTexture: state.hair.hairTexture }
    };
    updateState({ baseImage: generatedImage, baseline: currentAsBaseline });
    setGeneratedImage(null);
    setResultAnalysis(null);
    setIsComparing(false);
  };

  const handleCopyAnalysis = () => {
    if (resultAnalysis) {
      navigator.clipboard.writeText(resultAnalysis);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }
  };

  const handleDeleteBaseImage = () => {
    updateState({ baseImage: null, baseline: undefined });
    setGeneratedImage(null);
    setResultAnalysis(null);
  };

  const handleResetCategory = (category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const updates: any = {};
      if (category === 'face') {
        updates.features = prev.baseline ? { ...INITIAL_FEATURES, ...prev.baseline.features } : INITIAL_FEATURES;
      } else if (category === 'skin') {
        updates.skin = prev.baseline ? { ...prev.skin, ...prev.baseline.skin } : { ...prev.skin, tone: 'natural', skinAge: 20 };
      } else if (category === 'hair') {
        updates.hair = prev.baseline && prev.baseline.hair ? { ...prev.hair, ...prev.baseline.hair } : INITIAL_HAIR;
      } else if (category === 'makeup') {
        updates.makeup = INITIAL_MAKEUP;
      }
      return { ...prev, ...updates };
    });
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const detectedRatio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: detectedRatio, baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String, detectedRatio);
            } catch (err) {
              setError("AI analysis failed.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-[#050505] overflow-hidden text-zinc-100 selection:bg-indigo-500/30">
      <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 bg-zinc-950/60 backdrop-blur-3xl z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-2xl shadow-indigo-600/30">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[9px] text-zinc-500 font-black uppercase tracking-[0.2em] mt-1">High-End Digital Aesthetics</p>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <button onClick={handleGenerate} disabled={isGenerating || !state.baseImage} className={`flex items-center gap-3 px-8 py-3 rounded-2xl font-black text-sm tracking-wide transition-all ${isGenerating || !state.baseImage ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-2xl shadow-indigo-600/40 border border-white/10'}`}>
            {isGenerating ? <div className="w-5 h-5 border-[3px] border-white/30 border-t-white rounded-full animate-spin" /> : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'SYNTHESIZING...' : 'START SYNTHESIS'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={handleResetCategory} />
        <div className="flex-1 p-8 flex flex-col gap-8 overflow-hidden bg-[#09090b]">
          {error && <div className="bg-rose-500/10 border border-rose-500/20 text-rose-400 px-5 py-3 rounded-2xl flex items-center justify-between text-xs font-bold shrink-0"><span>{error}</span><button onClick={() => setError(null)}>✕</button></div>}
