              </div>
              <div className="bg-zinc-900/30 border border-white/5 rounded-[40px] overflow-hidden flex flex-col relative shadow-2xl backdrop-blur-sm">
                <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/5">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Synthetic Output</h3>
                  {generatedImage && <div className="flex gap-2">
                    <button onClick={handleUseAsBase} className="text-[10px] font-black text-indigo-400 bg-indigo-500/10 px-3 py-1.5 rounded-full border border-indigo-500/20 hover:bg-indigo-500/20 transition-all active:scale-95 uppercase tracking-widest">BASE</button>
                    <button onClick={handleDownload} className="text-[10px] font-black text-emerald-400 bg-emerald-500/10 px-3 py-1.5 rounded-full border border-emerald-500/20 hover:bg-emerald-500/20 transition-all active:scale-95 uppercase tracking-widest">SAVE</button>
                    <button 
                      onMouseDown={() => setIsComparing(true)}
