                )}
              </div>
              <div className={`flex-1 overflow-y-auto text-[11px] leading-relaxed font-sans p-4 rounded-2xl border border-white/5 transition-all duration-500 ${generatedImage && resultAnalysis ? 'bg-emerald-500/5 text-emerald-100/80 italic' : 'bg-black/40 text-zinc-400 font-mono'}`}>
                {generatedImage && resultAnalysis ? (
                   <div className="whitespace-pre-wrap">
                     {resultAnalysis}
                   </div>
                ) : currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

