const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline === undefined) return `FIXED: Strictly maintain current ${type}.`;
  const diff = current - baseline;
  const absDiff = Math.abs(diff);

  if (absDiff < 5) return `FIXED: Strictly keep the original ${type} unchanged.`;

  let intensityVerb = "slightly adjust";
  if (absDiff > 40) intensityVerb = "DRAMATICALLY OVERHAUL and EXAGGERATE";
  else if (absDiff > 20) intensityVerb = "SIGNIFICANTLY MORPH";
  else intensityVerb = "NOTICEABLY modify";

  let action = "";
  if (diff > 0) {
    action = (type === 'mouthCorners') ? "forcefully lift and curve upwards into a visible smile contour" : "increase/sharpen/widen";
  } else {
    action = (type === 'jawShape' || type === 'cheekboneHeight') ? "heavily add soft tissue/flesh and round out into a plump curve, removing skeletal definition" : "decrease/soften/shrink/round";
  }

  // Force hairline awareness for foreheadHeight
  const prefix = type === 'foreheadHeight' ? "HAIRLINE REPOSITIONING: " : "MORPH GEOMETRY: ";

  return `${prefix}${intensityVerb} the ${type} to be ${getSliderAdjective(current, type)}. IMPORTANT: Only change the structural shape, do not alter surface colors or makeup pigments in this area.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: { 
        parts: [
          { inlineData: { data, mimeType } }, 
          { text: "Detailed anatomical facial analysis. Determine facial and skin percentages as INTEGERS between 0 and 100 (e.g., 50, 85). Return ONLY JSON." }
        ] 
      },
      config: { 
        responseMimeType: "application/json", 
        responseSchema: { 
          type: Type.OBJECT, 
          properties: { 
            skinTone: { type: Type.NUMBER, description: "Skin tone percentage 0-100" }, 
            skinAge: { type: Type.NUMBER, description: "Skin age percentage 0-100" }, 
            eyeSize: { type: Type.NUMBER, description: "Eye size percentage 0-100" }, 
            eyeTilt: { type: Type.NUMBER, description: "Eye tilt percentage 0-100" }, 
            noseBridge: { type: Type.NUMBER, description: "Nose bridge height percentage 0-100" }, 
            noseWidth: { type: Type.NUMBER, description: "Nose width percentage 0-100" }, 
            faceWidth: { type: Type.NUMBER, description: "Face width percentage 0-100" }, 
            cheekboneHeight: { type: Type.NUMBER, description: "Cheekbone height percentage 0-100" }, 
            jawShape: { type: Type.NUMBER, description: "Jaw shape percentage 0-100" }, 
            lipFullness: { type: Type.NUMBER, description: "Lip fullness percentage 0-100" }, 
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] }, 
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] } 
          }, 
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"] 
        } 
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) { throw error; }
};

export const analyzeResultingAesthetics = async (base64Image: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze this beauty portrait and provide a high-quality, professional photography prompt that describes it. Focus on model characteristics, skin texture, lighting, camera settings (like lens), and overall mood. The output should be a single, detailed paragraph." }
        ]
      }
    });
    return response.text || "Analysis unavailable.";
  } catch (error) {
    return "Result Analysis failed.";
  }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages, customPrompts } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "ABSOLUTE EXPRESSION LOCK: The subject's current facial expression, mouth opening/closure, and eye gaze must remain 100% UNCHANGED. Do not move a single facial muscle.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Replicate exact bone structure from FACIAL REF. Keep original expression if possible.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow', 'chinHeight', 'foreheadHeight'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) mods.push(`EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}`);

    faceIns = `STRUCTURAL MODIFICATION: ${mods.join(" | ")}. VERTICAL PROPORTIONING: Specifically adjust the hairline position to match the foreheadHeight setting. Maintain all other facial expressions exactly. ${customPrompts.face ? `CUSTOM FACE NOTE: ${customPrompts.face}` : ''}`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: Preserve all existing makeup colors and styles from the base image exactly.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    let foundationPrompt = "Foundation Base: Strictly preserve and anchor the original skin color and tone as seen in the base image.";
    if (makeup.foundationTone !== 'none') {
      const preset = FOUNDATION_SHADES.find(s => s.id === makeup.foundationTone);
      if (preset) {
        foundationPrompt = `Foundation Base: Apply a full-coverage layer of ${preset.prompt}. This new tone must completely override the old skin tone while keeping detail.`;
      } else if (makeup.foundationTone.startsWith('#')) {
        foundationPrompt = `Foundation Base: Apply a professional layer of custom foundation with hex color ${makeup.foundationTone}. Seal this color across all visible skin areas.`;
      }
    }

    const blushDesc = makeup.blushStyle !== 'none' 
      ? `Blush: Apply ${makeup.blushColor} in ${makeup.blushStyle} style with ${makeup.blushIntensity}% intensity.` 
      : "Blush: None.";
    const contourDesc = `Contour: Apply ${makeup.contourIntensity}% depth shading.`;

    makeIns = `COLOR-ONLY ARTISTRY: Apply the ${makeup.makeupStyle} palette. (DO NOT change facial expression or mouth pose to match the style). Foundation: ${foundationPrompt}. Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}. Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}. Lips: Apply ${makeup.lipColor} pigment onto the original lip shape. ${blushDesc} ${contourDesc}. ${customPrompts.makeup ? `ARTIST NOTE: ${customPrompts.makeup}` : ''}`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Maintain exact original skin tone and texture without any shifting.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and tone from SKIN REF.";
  } else {
    const skinStyle = SKIN_TEXTURES.find(t => t.id === skin.texture[0])?.prompt || "smooth skin";
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skinStyle}. Glow: ${skin.glowIntensity}%, Age: ${skin.skinAge}%, Blemish detail: ${skin.blemishIntensity}%. ${customPrompts.skin ? `SKIN NOTE: ${customPrompts.skin}` : ''}`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
    hairIns = `HAIR: ${hair.hairLength} length ${hair.hairTexture}. Bangs: ${selectedBang}. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%. HAIRSTYLE ADAPTATION: Ensure the hairstyle accommodates the new hairline position dictated by the foreheadHeight. ${customPrompts.hair ? `HAIR NOTE: ${customPrompts.hair}` : ''}`;
  }

  return `Task: High-End Editorial Retouching. 
    MANDATORY: PRESERVE ORIGINAL FACIAL EXPRESSION. The pose, mouth closure/opening, and facial muscle tension from the BASE IMAGE must be exactly maintained.
    FACIAL STRUCTURE: ${faceIns} 
    SURFACE COLORS & MAKEUP (COLOR ONLY): ${makeIns}
    SKIN QUALITY: ${skinIns} 
    HAIR: ${hairIns} 
    CRITICAL MANDATE: Separate Pose from Pigment. Any changes to makeup style must NOT affect the emotional expression or facial muscle position. Output 2K Ultra HD realistic portrait. Preserve original background.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const [header, data] = state.baseImage.split(';base64,');
    parts.push({ text: "SOURCE BASE IMAGE (ABSOLUTE REFERENCE FOR POSE AND EXPRESSION)" }, { inlineData: { data, mimeType: header.split(':')[1] } });
  }

  const addRef = (category: keyof typeof state.referenceImages, label: string) => {
    if (state.editModes[category] && state.referenceImages[category]) {
      const [header, data] = state.referenceImages[category]!.split(';base64,');
      parts.push({ text: `${label} REF IMAGE` }, { inlineData: { data, mimeType: header.split(':')[1] } });
    }
  };

  addRef('hair', 'HAIR');
  addRef('makeup', 'MAKEUP');
  addRef('skin', 'SKIN');
  addRef('face', 'FACIAL');

  try {
    const response = await ai.models.generateContent({ 
      model: 'gemini-3-pro-image-preview', 
      contents: { parts }, 
      config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } 
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { throw error; }
};

