export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages, customPrompts } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceIns = "";
  if (isTargetedEdit && !editModes.face) {
    faceIns = "ABSOLUTE EXPRESSION LOCK: The subject's current facial expression, mouth opening/closure, and eye gaze must remain 100% UNCHANGED. Do not move a single facial muscle.";
  } else if (referenceImages.face) {
    faceIns = "ANATOMICAL CLONING: Replicate exact bone structure from FACIAL REF. Keep original expression if possible.";
  } else {
    const mods: string[] = [];
    const keys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'jawShape', 'mouthCorners', 'lipCupidBow', 'chinHeight', 'foreheadHeight'];
    keys.forEach(k => mods.push(getDiffFeaturePrompt((features as any)[k], (baseline?.features as any)?.[k], k)));

    // Eyebrow style check
    const browIns = makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle 
      ? `EYEBROWS: ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle]}` 
      : "EYEBROWS: Preserve the exact original eyebrow shape and density from the base image.";
    mods.push(browIns);

    faceIns = `STRUCTURAL MODIFICATION: ${mods.join(" | ")}. VERTICAL PROPORTIONING: Specifically adjust the hairline position to match the foreheadHeight setting. Maintain all other facial expressions exactly. ${customPrompts.face ? `CUSTOM FACE NOTE: ${customPrompts.face}` : ''}`;
  }

  let makeIns = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeIns = "STRICT LOCK: Preserve all existing makeup colors and styles from the base image exactly.";
  } else if (referenceImages.makeup) {
    makeIns = "MAKEUP TRANSFER: Copy exact eyeliner, eyeshadow, and lip colors from MAKEUP REF.";
  } else {
    // Determine which parts of the makeup are actually modified
    const isFoundationModified = makeup.foundationTone !== INITIAL_MAKEUP.foundationTone;
    const isEyelinerModified = makeup.eyelinerStyle !== INITIAL_MAKEUP.eyelinerStyle;
    const isEyelashModified = makeup.eyelashStyle !== INITIAL_MAKEUP.eyelashStyle;
    const isLipModified = makeup.lipColor !== INITIAL_MAKEUP.lipColor || makeup.lipStyle !== INITIAL_MAKEUP.lipStyle;
    const isBlushModified = makeup.blushStyle !== 'none' && makeup.blushIntensity > 30; // 30 is initial
    const isContourModified = makeup.contourIntensity !== INITIAL_MAKEUP.contourIntensity;

    let foundationPrompt = "Foundation: STRICTLY PRESERVE original skin color/tone exactly.";
    if (isFoundationModified) {
      if (makeup.foundationTone === 'none') {
        foundationPrompt = "Foundation: Revert to original raw skin tone.";
      } else {
        const preset = FOUNDATION_SHADES.find(s => s.id === makeup.foundationTone);
        foundationPrompt = preset 
          ? `Foundation: Apply ${preset.prompt} across all skin areas.` 
          : `Foundation: Apply custom shade ${makeup.foundationTone} to the skin.`;
      }
    }

    const eyelinerPrompt = isEyelinerModified 
      ? `Liner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle]}.` 
      : "Liner: PRESERVE ORIGINAL. Do not add or change eyeliner.";

    const lashPrompt = isEyelashModified 
      ? `Lashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle]}.` 
      : "Lashes: PRESERVE ORIGINAL. Do not add or change eyelashes.";

    const lipPrompt = isLipModified 
      ? `Lips: Apply ${makeup.lipColor} pigment in ${makeup.lipStyle} style.` 
      : "Lips: PRESERVE ORIGINAL. Keep the original natural lip color and texture from the base image.";

    const blushPrompt = isBlushModified 
      ? `Blush: Apply ${makeup.blushColor} in ${makeup.blushStyle} style (${makeup.blushIntensity}%).` 
      : "Blush: PRESERVE ORIGINAL. Do not add cheek color.";

    const contourPrompt = isContourModified 
      ? `Contour: Add ${makeup.contourIntensity}% depth shading.` 
      : "Contour: PRESERVE ORIGINAL. Keep original facial shadows.";

    const styleContext = makeup.makeupStyle !== 'Custom Look' 
      ? `STYLE CONCEPT: Adhere to the ${makeup.makeupStyle} aesthetic only for the modified parts.` 
      : "STYLE CONCEPT: Natural custom enhancements.";

    makeIns = `CONSERVATIVE ARTISTRY: ${styleContext} ${foundationPrompt} ${eyelinerPrompt} ${lashPrompt} ${lipPrompt} ${blushPrompt} ${contourPrompt}. (MANDATORY: Preserve facial expression). ${customPrompts.makeup ? `ARTIST NOTE: ${customPrompts.makeup}` : ''}`;
  }

  let skinIns = "";
  if (isTargetedEdit && !editModes.skin) {
    skinIns = "STRICT LOCK: Maintain exact original skin tone and texture without any shifting.";
  } else if (referenceImages.skin) {
    skinIns = "DERMAL CLONE: Replicate skin texture and tone from SKIN REF.";
  } else {
    const skinStyle = SKIN_TEXTURES.find(t => t.id === skin.texture[0])?.prompt || "smooth skin";
    skinIns = `DERMATOLOGY: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skinStyle}. Glow: ${skin.glowIntensity}%, Age: ${skin.skinAge}%, Blemish detail: ${skin.blemishIntensity}%. ${customPrompts.skin ? `SKIN NOTE: ${customPrompts.skin}` : ''}`;
  }

  let hairIns = "";
  if (isTargetedEdit && !editModes.hair) {
    hairIns = "STRICT LOCK: No hair changes.";
  } else if (referenceImages.hair) {
    hairIns = "HAIR REPLACEMENT: Copy length, texture, and color from HAIR REF.";
  } else {
    const selectedBang = BANG_STYLES.find(b => b.id === hair.bangStyle)?.label || 'none';
    hairIns = `HAIR: ${hair.hairLength} length ${hair.hairTexture}. Bangs: ${selectedBang}. Color: ${hair.hairColorTop} to ${hair.hairColorBottom}. Volume: ${hair.hairVolume}%. HAIRSTYLE ADAPTATION: Ensure the hairstyle accommodates the new hairline position. ${customPrompts.hair ? `HAIR NOTE: ${customPrompts.hair}` : ''}`;
  }

  return `Task: Professional Beauty Retouching. 
    MANDATORY RULE: SELECTIVE EDITING. Only modify features explicitly requested. All other features (eyes, lips, expression, background) must remain 100% IDENTICAL to the BASE IMAGE.
    FACIAL STRUCTURE: ${faceIns} 
    SURFACE COLORS & MAKEUP (SELECTIVE): ${makeIns}
    SKIN QUALITY: ${skinIns} 
    HAIR: ${hairIns} 
    CRITICAL MANDATE: Separate Pose from Pigment. Output 2K Ultra HD realistic portrait. Preserve original background and lighting ambiance.`;
};

