  canthalTilt: number; // eyeTilt
  jawShape: number;
  cheekboneHeight: number;
  faceWidth: number;
  eyeDistance: number;
  noseBridge: number;
  mouthCorners: number;
  lipCupidBow: number;
  chinHeight: number;
  foreheadHeight: number;
}

export interface SkinFeatures {
  tone: string;
